#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; if(scanf("%d", &n)!=1) return 0;
        long long prev, x;
        long long ans = 1, cur = 1;
        if(n==0){ printf("0\n"); continue; }
        scanf("%lld", &prev);
        for(int i=1;i<n;i++){
            scanf("%lld", &x);
            if(x>prev) cur++; else cur=1;
            if(cur>ans) ans=cur;
            prev = x;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

