import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        if n == 0:
            out.append('0')
            continue
        prev = int(next(it))
        cur = ans = 1
        for _ in range(1, n):
            x = int(next(it))
            if x > prev:
                cur += 1
            else:
                cur = 1
            if cur > ans:
                ans = cur
            prev = x
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

